SPARQL PREFIX otm: <http://www.semanticweb.org/adriano/ontologies/2014/7/ontologia-atlante-3.0#>
SELECT DISTINCT ?s ?label ?wkt ?ic ?p WHERE {
  ?s rdf:type otm:Parcheggi .
  ?s rdfs:label ?label .
  ?s <http://www.opengis.net/ont/geosparql#defaultGeometry> ?geometry .
  ?geometry <http://www.opengis.net/ont/geosparql#asWKT> ?wkt .
  OPTIONAL { ?s otm:is_crowdsourced ?ic } .
  OPTIONAL { ?s otm:id_progetto ?p } .
  FILTER ( bif:st_may_intersect(
    ?wkt,
    bif:st_geomfromtext("POLYGON((7.153472900390625 45.22751340428295,8.208160400390625 45.22751340428295,8.208160400390625 44.8996597828752,7.153472900390625 44.8996597828752,7.153472900390625 45.22751340428295))")
  ))
} LIMIT 5;
